PRAGMA foreign_keys = ON;

CREATE TABLE IF NOT EXISTS swords (id INTEGER PRIMARY KEY AUTOINCREMENT, n TEXT NOT NULL, c TEXT NOT NULL, v INTEGER NOT NULL, d TEXT NOT NULL, t TEXT NOT NULL, ct INTEGER, u TEXT NOT NULL, descr TEXT NOT NULL DEFAULT '', image_key TEXT, edited INTEGER NOT NULL DEFAULT 0 CHECK (edited IN (0, 1))); 
CREATE TABLE IF NOT EXISTS sword_baseline (id INTEGER PRIMARY KEY, n TEXT NOT NULL, c TEXT NOT NULL, v INTEGER NOT NULL, d TEXT NOT NULL, t TEXT NOT NULL, ct INTEGER, u TEXT NOT NULL, descr TEXT NOT NULL DEFAULT '', image_key TEXT, edited INTEGER NOT NULL DEFAULT 0 CHECK (edited IN (0, 1))); 
CREATE TABLE IF NOT EXISTS admin_config (config_key TEXT PRIMARY KEY, secret TEXT NOT NULL, issuer TEXT NOT NULL, account_label TEXT NOT NULL, digits INTEGER NOT NULL, period INTEGER NOT NULL, updated_at TEXT NOT NULL); 
CREATE TABLE IF NOT EXISTS rate_limits (bucket TEXT NOT NULL, limiter_key TEXT NOT NULL, request_count INTEGER NOT NULL DEFAULT 0, window_start INTEGER NOT NULL, PRIMARY KEY (bucket, limiter_key)); 
CREATE INDEX IF NOT EXISTS idx_swords_category ON swords (c);
CREATE INDEX IF NOT EXISTS idx_swords_value ON swords (v DESC);
CREATE INDEX IF NOT EXISTS idx_sword_baseline_category ON sword_baseline (c);
CREATE INDEX IF NOT EXISTS idx_rate_limits_window_start ON rate_limits (window_start);

DELETE FROM swords;
DELETE FROM sword_baseline;

